"use client";

import { useEffect, useRef, useState } from "react";

const LINES = [
  "I told her it didn't matter anymore.",
  "That I had made peace with it.",
  "I smiled when I said it.",
  "",
  "I still check her profile every night.",
  "if it was right.",
];

interface ParchmentIntroProps {
  onComplete: () => void;
}

export default function ParchmentIntro({ onComplete }: ParchmentIntroProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [textOpacity, setTextOpacity] = useState(1);
  const [fading, setFading] = useState(false);
  const doneFiredRef = useRef(false);
  const onCompleteRef = useRef(onComplete);

  useEffect(() => { onCompleteRef.current = onComplete; }, [onComplete]);

  // Autoplay on mount
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    video.play().catch(() => {});
  }, []);

  // Fade text as video plays, complete when video ends
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleTimeUpdate = () => {
      const duration = video.duration;
      if (!duration) return;
      const progress = video.currentTime / duration;
      const opacity =
        progress < 0.2 ? 1 :
        progress > 0.8 ? 0 :
        1 - (progress - 0.2) / 0.6;
      setTextOpacity(opacity);
    };

    const handleEnded = () => {
      if (doneFiredRef.current) return;
      doneFiredRef.current = true;
      setFading(true);
      setTimeout(() => onCompleteRef.current(), 800);
    };

    video.addEventListener("timeupdate", handleTimeUpdate);
    video.addEventListener("ended", handleEnded);
    return () => {
      video.removeEventListener("timeupdate", handleTimeUpdate);
      video.removeEventListener("ended", handleEnded);
    };
  }, []);

  const skip = () => {
    if (doneFiredRef.current) return;
    doneFiredRef.current = true;
    setFading(true);
    setTimeout(() => onCompleteRef.current(), 800);
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center cursor-pointer"
      style={{ background: "#0f0c08" }}
      onClick={skip}
    >
      <div
        style={{
          position:    "relative",
          width:       "min(90vw, calc(75vh * (896 / 1200)))",
          aspectRatio: "896 / 1200",
          opacity:     fading ? 0 : 1,
          transition:  "opacity 1s ease",
          overflow:    "hidden",
          boxShadow:   "0 16px 64px rgba(0,0,0,0.75), 0 4px 20px rgba(0,0,0,0.5)",
        }}
      >
        {/* Video — the burning paper */}
        <video
          ref={videoRef}
          src="/burn-effect.mp4"
          playsInline
          preload="auto"
          muted
          style={{
            position:  "absolute",
            inset:     0,
            width:     "100%",
            height:    "100%",
            objectFit: "cover",
          }}
        />

        {/* Text overlay — centered in the middle of the video */}
        <div
          style={{
            position:       "absolute",
            inset:          0,
            display:        "flex",
            flexDirection:  "column",
            alignItems:     "center",
            justifyContent: "center",
            padding:        "10%",
            boxSizing:      "border-box",
            opacity:        textOpacity,
            transition:     "opacity 0.15s linear",
            pointerEvents:  "none",
          }}
        >
          {LINES.map((line, i) => {
            const isLast = i === LINES.length - 1;
            return (
              <div
                key={i}
                style={{
                  minHeight:  line === "" ? "14px" : undefined,
                  fontFamily: "'Cormorant Garamond', Georgia, serif",
                  fontSize:   isLast ? "22px" : "17px",
                  fontWeight: isLast ? 400 : 300,
                  fontStyle:  isLast ? "italic" : "normal",
                  lineHeight: "2",
                  color:      "#1a0e04",
                  textAlign:  "center",
                }}
              >
                {line || "\u00A0"}
              </div>
            );
          })}
        </div>

        <p
          style={{
            position:   "absolute",
            bottom:     "14px",
            right:      "20px",
            fontSize:   "10px",
            color:      "#9a7840",
            fontFamily: "Georgia, serif",
            fontStyle:  "italic",
            opacity:    0.5,
          }}
        >
          tap to skip
        </p>
      </div>
    </div>
  );
}
